#include <bits/stdc++.h>
using namespace std;
const int N=1005,V=40005,M=20001;
const long long mod=998244353;
long long n,a[N],dp[N][V],ans;
int main()
{
	ios::sync_with_stdio(0);
	cin.tie(0),cout.tie(0);
	cin>>n;
	for(int i=1;i<=n;i++)
	{
		cin>>a[i];
	}
	for(int i=1;i<=n;i++)
	{
		ans=(ans+i)%mod;
		for(int j=i-1;j>=1;j--)
		{
			int cha=a[i]-a[j];
			ans=(ans+dp[j][cha+M])%mod;
			dp[i][M+cha]=(dp[i][cha+M]+dp[j][cha+M]+1)%mod;
		}
	}
	cout<<ans;
	return 0;
}
